  ('pukao-7ec62a85-moex-00003', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-114-06dee816', 'sub-pukao-7ec62a85-01', NULL, 'essay', '警察 B 為查緝 A 運輸槍械，7 月 8 日上午 6 時，在 A 駕駛車輛底盤安裝
GPS追蹤器。7月9日上午5時，B為避免被A識破，趁A將車停在商店
停車場，將GPS追蹤器取下。B取得A車輛行駛路線後，製作偵查報告，
提供予檢察官。經檢察官偵查終結，綜合其他證據，向法院提起公訴。請
分析A主張本件GPS追蹤位置違法且無證據能力有無理由。（35分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "3e87a6ea24c2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "417", "s": "0916", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00004', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-114-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列國際法作為行政法法源之敘述，何者錯誤？', '["條約涉及人民之權利義務且具有法律上效力者，應送立法院審議", "條約與立法院制定之法律相牴觸時，應優先適用國內法律", "國際法須於條約或協定明定其內容，始可引用作為行政法法源", "經憲法法庭直接引用之國際公約，可以於授益行政的範圍內引用之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "417", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00005', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-114-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '行政程序法第5條規定：「行政行為之內容應明確」，下列敘述何者正確？', '["懲處之構成要件，法律不得以抽象概念表示", "所謂內容應該明確，僅限於行政處分", "書面行政處分書雖漏未記載處分相對人之性別，但已有足資辨別之特徵者，符合明確性原則", "行政指導無需符合明確性原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "417", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00006', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-114-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '行政機關核發甲之商場開發許可時，因甲不能提供足夠之停車位，而要求其提供金錢改善社區之照明設施， 此要求違反下列何原則？', '["比例原則", "不當聯結禁止原則", "誠信原則", "平等原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "417", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00007', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-114-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '行政機關應依下列何種方式行使裁量權？', '["為實現行政任務，得附加法律規定所無之條件", "為實現行政任務，得考量法律授權目的以外之因素", "應採取裁量基準所定最小干預方式，無須考量個案情節之差異", "應視個案事實情況、衡酌規範目的，進行合義務裁量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "417", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('pukao-7ec62a85-moex-00008', 'pukao-7ec62a85', 'pukao-7ec62a85-moex-114-d1a761c9', 'sub-pukao-7ec62a85-02', NULL, 'single_choice', '下列何種私經濟行為不具給付行政功能？', '["社會住宅之出租", "辦公廳舍之租用", "水電瓦斯之供應", "大眾運輸交通之經營"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:41+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "417", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "法律廉政"}'::jsonb, NULL),
